#include <bits/stdc++.h>
using namespace std;
int n,a[100005],p[100005];
int dp[100005];
int main(){
    memset(dp,127,sizeof(dp));
	scanf("%d",&n);
	for(int i=1;i<=n;i++)
		scanf("%d",&a[i]);
	for(int i=1;i<=n;i++){
		int b;
		scanf("%d",&b);
		p[b]=i;
	}
	for(int i=1;i<=n;i++)
		a[i]=p[a[i]];
	int len=0;
	dp[0]=0;
	for(int i=1;i<=n;i++){
		if(dp[len]<a[i])
			dp[++len]=a[i];
		else{
			int l=0,r=len;
			while(l<r){
				int mid=(l+r)/2;
				if(dp[mid]>a[i])
					r=mid;
				else
					l=mid+1;
			}
			dp[l]=min(dp[l],a[i]);
		}
	}
	printf("%d",len);
	return 0;
}
